def run_length_encode(s):
    if not s:
        return ""
    result = ""
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i - 1]:
            count += 1
        else:
            result += s[i - 1] + str(count)
            count = 1
    result += s[-1] + str(count)
    return result

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic_groups(self):
        self.assertEqual(run_length_encode("aaabbbcc"), "a3b3c2")

    def test_all_unique(self):
        self.assertEqual(run_length_encode("abc"), "a1b1c1")

    def test_non_adjacent_repeats(self):
        self.assertEqual(run_length_encode("aabba"), "a2b2a1")

    def test_hidden_empty_string(self):
        self.assertEqual(run_length_encode(""), "")

    def test_hidden_single_char(self):
        self.assertEqual(run_length_encode("a"), "a1")

    def test_hidden_all_same(self):
        self.assertEqual(run_length_encode("aaa"), "a3")

    def test_hidden_pairs(self):
        self.assertEqual(run_length_encode("aabbcc"), "a2b2c2")

    def test_hidden_large_count(self):
        self.assertEqual(run_length_encode("a" * 10), "a10")

    def test_hidden_alternating(self):
        self.assertEqual(run_length_encode("ababab"), "a1b1a1b1a1b1")

    def test_hidden_mixed_lengths(self):
        self.assertEqual(run_length_encode("aaabcdddd"), "a3b1c1d4")

if __name__ == '__main__':
    unittest.main()
